| MCP:yq7PUL | #!/usr/bin/env bash
| MCP:yq7PUL | set -euo pipefail
| MCP:yq7PUL | TARGET=${1:-http://host.docker.internal:8080}
| MCP:yq7PUL | case "$TARGET" in
| MCP:yq7PUL |   http://127.0.0.1:*|http://localhost:*|http://host.docker.internal:*) ;;
| MCP:yq7PUL |   *) echo "Refusing non-local target: $TARGET" >&2; exit 2 ;;
| MCP:yq7PUL | esac
| MCP:yq7PUL | docker run --rm -t -v "$(pwd):/zap/wrk" ghcr.io/zaproxy/zaproxy:stable zap-baseline.py -t "$TARGET" -c zap/baseline.conf -J reports/zap_baseline.json || true
